def main():
    data = sys.stdin.read().strip().splitlines()
    i = 0
    while i < len(data):
        name1, name2 = data[i].split()
        p1, p2 = map(int, data[i+1].split())
        if p1 > p2:
            print(name1)
        elif p2 > p1:
            print(name2)
        else:
            print("**equal**")
        i += 2

if __name__ == "__main__":
