const readline = require('readline').createInterface({
  input: process.stdin,
  output: process.stdout
});

let i = 0;
let input = [];
readline.on('line', line => {
  input.push(line);
  i++;
  if (i % 2 == 0) {
    const [name1, name2] = input[i-2].trim().split(' ');
    const [p1Str, p2Str] = input[i-1].trim().split(' ');
    const p1 = parseInt(p1Str, 10);
    const p2 = parseInt(p2Str, 10);
    if (p1 > p2) console.log(name1);
    else if (p2 > p1) console.log(name2);
    else console.log('**equal**');
  }
});
